// SEED EVERGREEN — GET /api/seed-evergreen?key=espana2025
app.get('/api/seed-evergreen', (req, res) => {
  if (req.query.key !== 'espana2025') return res.status(403).json({error:'forbidden'});
  try {
    const dbPath = fs.existsSync(DB_PATH) ? DB_PATH : DB_LOCAL;
    const db = JSON.parse(fs.readFileSync(dbPath, 'utf8'));
    db.articles = db.articles || [];
    const ARTS = [
      {cat:'immigration',title:'كيف تهاجر إلى إسبانيا قانونياً في 2026 — دليل شامل خطوة بخطوة',summary:'دليل شامل ومحدث لعام 2026 يشرح كل الطرق القانونية للهجرة إلى إسبانيا.',tags:['هجرة','إسبانيا','تأشيرة','إقامة','2026'],content:'<h2>لماذا إسبانيا وجهة مفضلة للعرب؟</h2><p>تُعدّ إسبانيا من أكثر الدول الأوروبية استقطاباً للمقيمين العرب، بفضل مناخها الدافئ وتكلفة معيشتها المعقولة مقارنةً بدول غرب أوروبا.</p><h2>الطرق القانونية للهجرة</h2><h3>1. تأشيرة العمل</h3><p>الطريق الأكثر شيوعاً. يشترط وجود عرض عمل من صاحب عمل إسباني مسجّل.</p><ul><li>مدة المعالجة: 1 إلى 3 أشهر</li><li>تُمنح إقامة أولى لمدة سنة قابلة للتجديد</li></ul><h3>2. التأشيرة الذهبية للمستثمرين</h3><p>مخصصة لمن يستثمر في إسبانيا بمبلغ لا يقل عن 500,000 يورو في عقارات.</p><h3>3. تأشيرة العمل الحر</h3><p>لمن يخطط لفتح مشروع خاص أو العمل مستقلاً.</p><h3>4. تأشيرة لمّ الشمل العائلي</h3><p>لمن لديه قريب من الدرجة الأولى مقيم بشكل قانوني في إسبانيا.</p><h3>5. تأشيرة الطلاب</h3><p>للالتحاق بجامعة أو مؤسسة تعليمية إسبانية.</p><h2>الخطوات العملية</h2><ul><li>تحديد نوع التأشيرة المناسب</li><li>جمع المستندات المطلوبة</li><li>حجز موعد في القنصلية الإسبانية</li><li>تقديم الطلب ودفع الرسوم</li><li>انتظار القرار وترتيب السفر</li></ul>'},
      {cat:'residency',title:'كيف تجدد إقامتك في إسبانيا خطوة بخطوة 2026',summary:'دليل عملي ومحدث لتجديد بطاقة الإقامة في إسبانيا 2026، يشمل المستندات والمواعيد والرسوم.',tags:['إقامة','تجديد','وثائق','مكتب الأجانب','إسبانيا'],content:'<h2>متى تبدأ إجراءات التجديد؟</h2><p>يُنصح بالبدء قبل 60 يوماً من تاريخ الانتهاء على الأقل.</p><h2>المستندات المطلوبة</h2><ul><li>استمارة EX-17 مكتملة وموقعة</li><li>جواز السفر ساري المفعول وصورة منه</li><li>بطاقة الإقامة الحالية وصورة منها</li><li>صورة شخصية حديثة بخلفية بيضاء</li><li>شهادة التسجيل في البلدية حديثة</li><li>إثبات الوضع الاقتصادي: آخر 3 نومينا</li><li>إيصال دفع رسوم Tasa 790</li></ul><h2>خطوات التجديد</h2><ul><li>احجز موعداً مسبقاً قبل 30 يوماً</li><li>ادفع الرسوم في أي بنك إسباني</li><li>احضر في الموعد بكل الأوراق</li><li>استلم الإيصال الرسمي</li><li>انتظر 1-3 أشهر لاستلام البطاقة</li></ul><h2>أبرز الأخطاء الشائعة</h2><ul><li>التأخر في حجز الموعد</li><li>نسيان نسخة من الوثائق</li><li>دفع رسوم الكود الخاطئ</li></ul>'},
      {cat:'jobs',title:'حقوقك كعامل في إسبانيا — ما لا يخبرك به صاحب العمل',summary:'دليل شامل بحقوق العمال في إسبانيا 2026، يشمل الراتب والإجازات والتأمين والفصل التعسفي.',tags:['عمل','حقوق','راتب','إجازة','ضمان اجتماعي'],content:'<h2>الحد الأدنى للأجور 2026</h2><p>يبلغ الحد الأدنى للأجور 1,134 يورو شهرياً. أي عقد يدفع أقل يُعدّ مخالفاً للقانون.</p><h2>حقوقك الأساسية</h2><h3>العقد والتسجيل</h3><ul><li>من حقك الحصول على عقد مكتوب قبل بدء العمل</li><li>صاحب العمل ملزم بتسجيلك في الضمان الاجتماعي من أول يوم</li></ul><h3>ساعات العمل</h3><ul><li>الحد الأقصى 40 ساعة أسبوعياً</li><li>الساعات الإضافية تُدفع بنسبة 25% إضافية</li></ul><h3>الإجازات</h3><ul><li>30 يوم تقويمي إجازة سنوية مدفوعة</li><li>14 يوم إجازة رسمية مدفوعة سنوياً</li></ul><h2>حقوقك عند الفصل</h2><ul><li>الفصل التعسفي: 33 يوم راتب عن كل سنة عمل</li><li>حق الطعن في قرار الفصل خلال 20 يوماً</li></ul>'},
      {cat:'housing',title:'أرخص 5 مدن للسكن في إسبانيا للعرب في 2026',summary:'مقارنة شاملة لأسعار الإيجار في أرخص المدن الإسبانية للمقيمين العرب.',tags:['سكن','إيجار','مدن','تكلفة المعيشة','إسبانيا'],content:'<h2>أرخص 5 مدن 2026</h2><h3>1. مورسية</h3><p>الأرخص في إسبانيا. شقة غرفتين: 500-650 يورو شهرياً.</p><ul><li>✅ جالية عربية كبيرة</li><li>✅ مناخ دافئ وشمسي</li><li>❌ فرص العمل أقل</li></ul><h3>2. سرقسطة</h3><p>شقة غرفتين: 600-800 يورو.</p><ul><li>✅ سوق عمل جيد في الصناعة</li><li>❌ شتاء بارد</li></ul><h3>3. غرناطة</h3><p>شقة غرفتين: 550-750 يورو.</p><ul><li>✅ تراث عربي وإسلامي غني</li></ul><h3>4. إشبيلية</h3><p>شقة غرفتين: 650-900 يورو.</p><ul><li>✅ سوق عمل جيد ومتنامٍ</li></ul><h3>5. بلنسية</h3><p>شقة غرفتين: 700-1,000 يورو.</p><ul><li>✅ شواطئ جميلة وحياة اجتماعية نشطة</li></ul>'},
      {cat:'education',title:'الدراسة في إسبانيا مجاناً — المنح الدراسية والجامعات',summary:'دليل شامل للمنح الدراسية المتاحة في إسبانيا للطلاب العرب وكيفية التقديم والجامعات الأفضل.',tags:['تعليم','منح دراسية','جامعات','إسبانيا','طلاب'],content:'<h2>أبرز المنح المتاحة</h2><h3>1. منح Becas MEC</h3><p>متاحة للطلاب المقيمين. تُغطي رسوم التسجيل وجزءاً من تكاليف المعيشة.</p><h3>2. منح AECID</h3><p>للطلاب الأجانب — ماجستير ودكتوراه. تشمل رسوم الدراسة + 1,100 يورو شهرياً.</p><h3>3. منح الجامعات</h3><p>كثير من الجامعات تُقدم منحاً للطلاب المتميزين.</p><h2>أفضل الجامعات</h2><ul><li>جامعة برشلونة — الأعلى تصنيفاً</li><li>جامعة مدريد المستقلة</li><li>جامعة غرناطة — تراث عربي ورسوم منخفضة</li><li>البوليتيكنيكا مدريد — الأفضل في الهندسة</li></ul>'},
      {cat:'cost-of-living',title:'تكلفة المعيشة في إسبانيا بالتفصيل 2026',summary:'دليل شامل لتكاليف المعيشة في إسبانيا 2026 يشمل الإيجار والأكل والمواصلات والصحة.',tags:['تكلفة المعيشة','ميزانية','إيجار','أسعار','إسبانيا'],content:'<h2>كم تحتاج شهرياً؟</h2><p>يتفاوت المبلغ بين 900 يورو في المدن الصغيرة و2,000 يورو في مدريد وبرشلونة.</p><h2>الإيجار</h2><ul><li>غرفة مشتركة: 300-600 يورو/شهر</li><li>استوديو: 500-900 يورو/شهر</li><li>شقة غرفتين: 800-1,800 يورو/شهر</li></ul><h2>الطعام</h2><ul><li>تسوق شهري: 150-250 يورو</li><li>وجبة في مطعم: 10-15 يورو</li><li>Menú del Día: 10-14 يورو</li></ul><h2>ميزانية تقديرية</h2><ul><li>حياة اقتصادية: 900-1,100 يورو/شهر</li><li>حياة مريحة في مدن متوسطة: 1,200-1,600 يورو/شهر</li><li>مدريد/برشلونة: 1,800-2,500 يورو/شهر</li></ul>'},
      {cat:'government-benefits',title:'كيف تحصل على إعانة البطالة في إسبانيا — الشروط والخطوات',summary:'دليل عملي للحصول على إعانة البطالة في إسبانيا يشمل الشروط والمبالغ وخطوات التقديم.',tags:['بطالة','إعانة','SEPE','حقوق','ضمان اجتماعي'],content:'<h2>شروط الاستحقاق</h2><ul><li>مسجّل في الضمان الاجتماعي 360 يوماً خلال السنوات الـ 6 الأخيرة</li><li>الفصل لا إرادي وليس استقالة</li><li>إقامة قانونية سارية</li></ul><h2>كم تبلغ الإعانة؟</h2><ul><li>180 يوماً الأولى: 70% من الراتب</li><li>من اليوم 181: 50% من الراتب</li><li>مدة: من 4 أشهر إلى 24 شهراً</li></ul><h2>خطوات التقديم</h2><ul><li>سجّل كباحث عن عمل في SEPE</li><li>تقدم خلال 15 يوم عمل من الفصل</li><li>قدّم المستندات المطلوبة</li></ul>'},
      {cat:'crime-safety',title:'أكثر المدن الإسبانية أماناً للعائلات العربية',summary:'مقارنة بين أكثر المدن الإسبانية أماناً للإقامة مع نصائح عملية لحماية نفسك وعائلتك.',tags:['أمان','جريمة','مدن','عائلات','إسبانيا'],content:'<h2>إسبانيا بشكل عام دولة آمنة</h2><p>تُصنَّف إسبانيا ضمن أكثر دول العالم أماناً. المشكلة الأكبر هي سرقات السياح.</p><h2>أكثر المدن أماناً</h2><h3>1. بيلباو</h3><p>معدل الجريمة منخفض جداً وجودة حياة ممتازة.</p><h3>2. سان سيباستيان</h3><p>من أجمل وأأمن مدن إسبانيا.</p><h3>3. سرقسطة</h3><p>هادئة نسبياً مع نسب جريمة أقل من المدن الكبرى.</p><h2>نصائح السلامة</h2><ul><li>لا تضع محفظتك في جيب الظهر</li><li>في المواصلات أمسك حقيبتك من الأمام</li><li>الطوارئ: 112</li></ul>'},
      {cat:'local-news',title:'أفضل الأحياء العربية في مدريد وبرشلونة — دليل المقيمين',summary:'دليل شامل لأفضل الأحياء التي يفضلها المقيمون العرب في مدريد وبرشلونة.',tags:['أحياء','مدريد','برشلونة','جالية عربية','سكن'],content:'<h2>أفضل الأحياء في مدريد</h2><h3>لافابييس</h3><p>قلب التنوع الثقافي. فيه مطاعم عربية ومحلات حلال وجوامع. السعر: 700-1,100 يورو.</p><h3>تيتوان</h3><p>مجتمع عربي كبير وأسعار معقولة. السعر: 650-1,000 يورو.</p><h2>أفضل الأحياء في برشلونة</h2><h3>إل رابال</h3><p>الحي الأكثر تنوعاً. مسجد كبير ومحلات عربية. السعر: 750-1,200 يورو.</p><h2>الخدمات العربية المتوفرة</h2><ul><li>جوامع ومصليات في معظم المدن</li><li>مدارس قرآنية وعربية للأطفال</li><li>محلات لحوم حلال منتشرة</li><li>مطاعم عربية في كل المدن الكبيرة</li></ul>'},
      {cat:'tourism',title:'أجمل 10 أماكن سياحية في إسبانيا لا تفوتك',summary:'قائمة بأجمل الأماكن السياحية في إسبانيا مع نصائح عملية لكل وجهة.',tags:['سياحة','إسبانيا','أماكن سياحية','الحمراء','برشلونة'],content:'<h2>أجمل 10 أماكن</h2><ul><li><strong>1. قصر الحمراء — غرناطة:</strong> تحفة معمارية إسلامية. احجز مسبقاً.</li><li><strong>2. ساغرادا فاميليا — برشلونة:</strong> كنيسة غاودي الشهيرة.</li><li><strong>3. متحف البرادو — مدريد:</strong> من أعظم متاحف الفن في العالم.</li><li><strong>4. طليطلة:</strong> مدينة الديانات الثلاث.</li><li><strong>5. شاطئ لا كونشا — سان سيباستيان:</strong> من أجمل شواطئ أوروبا.</li><li><strong>6. جامع قرطبة:</strong> تحفة إسلامية فريدة.</li><li><strong>7. الحي القوطي — برشلونة:</strong> أزقة تاريخية رائعة.</li><li><strong>8. بارك غويل — برشلونة:</strong> حديقة غاودي الساحرة.</li><li><strong>9. جزر الكناري:</strong> جنة استوائية.</li><li><strong>10. كامينيتو ديل ري — مالقة:</strong> مسار بين الجبال.</li></ul><h2>نصائح</h2><ul><li>أفضل وقت: مارس-مايو أو سبتمبر-نوفمبر</li><li>احجز التذاكر مسبقاً</li></ul>'},
      {cat:'tourism',title:'السياحة في إسبانيا بميزانية محدودة — دليل شامل',summary:'كيف تستمتع بإسبانيا بأقل تكلفة ممكنة — نصائح للسكن والأكل والمواصلات والأماكن المجانية.',tags:['سياحة','ميزانية','رخيص','نصائح','إسبانيا'],content:'<h2>السكن الرخيص</h2><ul><li>النزل (Hostels): 15-30 يورو للسرير</li><li>Airbnb: غرفة خاصة من 30-60 يورو/ليلة</li></ul><h2>الأكل بأقل تكلفة</h2><ul><li>Menú del Día: أول وثانٍ وحلوى وشراب بـ 10-14 يورو</li><li>Tapas مجانية في غرناطة مع المشروب</li></ul><h2>المواصلات الرخيصة</h2><ul><li>Flixbus: من مدريد لبرشلونة بـ 15-25 يورو</li><li>BlaBlaCar: مشاركة السيارة بأسعار منخفضة</li></ul><h2>أماكن مجانية</h2><ul><li>معظم متاحف مدريد مجانية في ساعات معينة</li><li>الشواطئ كلها مجانية</li><li>الحدائق العامة مجانية</li></ul>'},
      {cat:'business',title:'كيف تفتح مشروعاً تجارياً في إسبانيا كمقيم عربي — دليل 2026',summary:'خطوات عملية لفتح مشروع تجاري في إسبانيا للمقيمين العرب من اختيار الشكل القانوني حتى التسجيل.',tags:['أعمال','مشروع','Autónomo','شركة','ضرائب'],content:'<h2>الأشكال القانونية</h2><h3>1. العامل الحر (Autónomo)</h3><p>الأنسب للمشاريع الفردية. اشتراك شهري يبدأ من 200 يورو.</p><h3>2. شركة SL</h3><p>رأس مال 1 يورو فقط. ضريبة الشركات 25%.</p><h2>خطوات التسجيل</h2><ul><li>الحصول على NIE ساري</li><li>التسجيل في Hacienda — نموذج 037</li><li>التسجيل في RETA</li></ul><h2>قطاعات واعدة للعرب</h2><ul><li>المطاعم والمأكولات العربية والحلال</li><li>الاستيراد والتصدير مع الدول العربية</li><li>خدمات الترجمة والوساطة التجارية</li><li>التجارة الإلكترونية</li></ul>'},
      {cat:'business',title:'العمل الحر Autónomo في إسبانيا — الضرائب والتأمين والتسجيل',summary:'دليل شامل لنظام العمل الحر في إسبانيا يشمل التسجيل والضرائب والتأمين والمزايا.',tags:['Autónomo','عمل حر','ضرائب','ضمان اجتماعي','إسبانيا'],content:'<h2>كيف تسجل كـ Autónomo؟</h2><ul><li>سجّل نشاطك في Hacienda عبر نموذج Modelo 037</li><li>سجّل في RETA خلال 30 يوماً من بدء النشاط</li></ul><h2>نظام الحصص 2026</h2><ul><li>دخل أقل من 670 يورو/شهر: 200 يورو/شهر</li><li>دخل 670-1,300 يورو: 292 يورو/شهر</li></ul><h2>الضرائب</h2><ul><li>IRPF: نموذج Modelo 130 ربع سنوي</li><li>IVA: 21% نموذج Modelo 303</li></ul><h2>المزايا</h2><ul><li>تأمين صحي كامل</li><li>إعانة بطالة بعد 12 شهراً</li><li>بناء حقوق المعاش</li></ul>'},
      {cat:'residency',title:'الإقامة الدائمة في إسبانيا — متى تحصل عليها وما هي شروطها',summary:'دليل شامل للحصول على الإقامة الدائمة في إسبانيا بعد 5 سنوات وما تمنحه من حقوق.',tags:['إقامة دائمة','5 سنوات','وثائق','جنسية','إسبانيا'],content:'<h2>ما هي الإقامة الدائمة؟</h2><p>وضع قانوني يمنحك حق الإقامة والعمل بشكل شبه دائم بعد 5 سنوات من الإقامة القانونية.</p><h2>الشروط</h2><ul><li>5 سنوات إقامة قانونية مستمرة</li><li>عدم الغياب أكثر من 10 أشهر متراكمة</li><li>عدم وجود سجل جنائي</li><li>إثبات كفاية مالية</li></ul><h2>المزايا</h2><ul><li>تجديد كل 5 سنوات فقط</li><li>حق العمل في أي قطاع</li><li>نفس مزايا المواطن في التعليم والصحة</li></ul>'},
      {cat:'jobs',title:'كيف تبحث عن عمل في إسبانيا بدون خبرة 2026',summary:'نصائح عملية للباحثين عن عمل في إسبانيا بدون خبرة من القطاعات الأسهل إلى كتابة السيرة الذاتية.',tags:['عمل','وظائف','بدون خبرة','CV','إسبانيا'],content:'<h2>أسهل القطاعات بدون خبرة</h2><h3>1. الضيافة والمطاعم</h3><p>الراتب: 1,100-1,400 يورو/شهر. مطلوب إسبانية أساسية.</p><h3>2. النظافة والتنظيف</h3><p>الراتب: 900-1,200 يورو/شهر. لا شيء مطلوب سوى الموثوقية.</p><h3>3. المستودعات واللوجستيك</h3><p>الراتب: 1,200-1,500 يورو/شهر.</p><h2>أين تبحث؟</h2><ul><li>InfoJobs.net — الأكبر في إسبانيا</li><li>Indeed.es — آلاف الوظائف يومياً</li><li>Job&amp;Talent — للوظائف الفورية</li></ul>'},
      {cat:'housing',title:'كيف تستأجر شقة في إسبانيا — الوثائق والخطوات والتكاليف',summary:'دليل عملي لاستئجار شقة في إسبانيا من البحث حتى توقيع العقد مع تفصيل التكاليف والوثائق.',tags:['إيجار','شقة','عقد','وديعة','إسبانيا'],content:'<h2>الوثائق المطلوبة</h2><ul><li>NIE أو جواز سفر ساري</li><li>عقد عمل أو آخر 3 كشوف رواتب</li><li>آخر كشف حساب بنكي</li></ul><h2>التكاليف عند الدخول</h2><ul><li>أول شهر إيجار مقدماً</li><li>وديعة: شهر إيجار على الأقل</li><li>جهّز مبلغ 2-4 أشهر إيجار للبداية</li></ul><h2>تحذيرات من الاحتيال</h2><ul><li>لا تحوّل أي مال قبل رؤية الشقة</li><li>أي سعر أقل بكثير من السوق = احتيال</li></ul>'},
      {cat:'education',title:'كيف تتعلم اللغة الإسبانية بسرعة مجاناً',summary:'أفضل الطرق والموارد المجانية لتعلم الإسبانية بسرعة من التطبيقات إلى الدورات الرسمية.',tags:['إسبانية','تعلم لغة','مجاني','Duolingo','اندماج'],content:'<h2>أفضل الموارد المجانية</h2><h3>Duolingo</h3><p>مثالي للمبتدئين، 15 دقيقة يومياً تكفي.</p><h3>Language Transfer</h3><p>دورة صوتية مجانية. في 40 ساعة ستتحدث إسبانية جيدة. languagetransfer.org</p><h3>YouTube</h3><ul><li>Dreaming Spanish — إسبانية بسيطة بالصور</li></ul><h2>خطة تعلم</h2><ul><li>الشهر 1-2: Duolingo + Language Transfer</li><li>الشهر 3-4: مسلسلات إسبانية بترجمة</li><li>الشهر 5-6: التحدث مع إسبان عبر Tandem</li></ul>'},
      {cat:'cost-of-living',title:'مقارنة تكلفة المعيشة في مدريد وبرشلونة وبلنسية',summary:'مقارنة تفصيلية لتكاليف المعيشة في أكبر 3 مدن إسبانية لمساعدتك على اختيار المدينة.',tags:['مدريد','برشلونة','بلنسية','تكلفة المعيشة','مقارنة'],content:'<h2>الإيجار</h2><ul><li>مدريد: شقة غرفتين 1,100-1,800 يورو</li><li>برشلونة: شقة غرفتين 1,200-2,000 يورو</li><li>بلنسية: شقة غرفتين 700-1,100 يورو</li></ul><p>بلنسية أرخص بـ 35-45%.</p><h2>الخلاصة</h2><ul><li>اختر مدريد للمال والقانون والإعلام</li><li>اختر برشلونة للتكنولوجيا والسياحة</li><li>اختر بلنسية لجودة حياة عالية بتكلفة معقولة</li></ul>'},
      {cat:'government-benefits',title:'مزايا الضمان الاجتماعي في إسبانيا للمقيمين العرب',summary:'دليل شامل لمزايا الضمان الاجتماعي في إسبانيا للمقيمين العرب من التأمين الصحي إلى التقاعد.',tags:['ضمان اجتماعي','تأمين صحي','تقاعد','مزايا','إسبانيا'],content:'<h2>التأمين الصحي</h2><ul><li>الرعاية الصحية الأولية مجانية</li><li>العمليات الجراحية في المستشفيات العامة</li><li>أدوية مدعومة بنسبة 40-90%</li><li>رعاية الأسرة الكاملة</li></ul><h2>إجازة الأمومة والأبوة</h2><p>الأم والأب: 16 أسبوعاً مدفوعة 100%.</p><h2>معاش التقاعد</h2><ul><li>سن التقاعد: 66 سنة و8 أشهر في 2026</li><li>الحد الأدنى: نحو 750 يورو/شهر</li></ul>'},
      {cat:'immigration',title:'تأشيرة الإقامة في إسبانيا — أنواعها وشروط الحصول عليها',summary:'دليل شامل لأنواع تأشيرات الإقامة في إسبانيا وشروط كل منها لمساعدتك على الاختيار الأنسب.',tags:['تأشيرة','إقامة','هجرة','عمل','إسبانيا'],content:'<h2>أنواع التأشيرات</h2><h3>1. تأشيرة العمل المأجور</h3><p>صاحب العمل يتقدم بطلب التصريح أولاً. مدة المعالجة 1-3 أشهر.</p><h3>2. التأشيرة الذهبية</h3><p>500,000 يورو في عقارات أو مليون يورو في أسهم.</p><h3>3. تأشيرة العمل الحر</h3><p>تقديم خطة عمل مفصّلة وإثبات كفاية مالية.</p><h3>4. تأشيرة الدراسة</h3><p>تُتيح العمل 20 ساعة أسبوعياً.</p><h3>5. لمّ الشمل العائلي</h3><p>للزوج والأبناء القاصرين.</p><h2>نصائح</h2><ul><li>جهّز ملفاً كاملاً قبل الموعد</li><li>ترجم جميع الوثائق ترجمة معتمدة</li></ul>'},
    ];
    let added = 0, skipped = 0;
    for (const a of ARTS) {
      const slug = (a.title||'').replace(/[^\u0600-\u06FF\s]/g,'').replace(/\s+/g,'-').substring(0,80).replace(/-+$/,'');
      if (db.articles.some(x => x.arabic_slug === slug || x.title === a.title)) { skipped++; continue; }
      const CAT_IMAGES = {
        'immigration':        'https://images.unsplash.com/photo-1436491865332-7a61a109cc05?w=800&q=80',
        'residency':          'https://images.unsplash.com/photo-1568992687947-868a62a9f521?w=800&q=80',
        'jobs':               'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80',
        'housing':            'https://images.unsplash.com/photo-1560518883-ce09059eeffa?w=800&q=80',
        'education':          'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=800&q=80',
        'cost-of-living':     'https://images.unsplash.com/photo-1579621970563-ebec7560ff3e?w=800&q=80',
        'government-benefits':'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800&q=80',
        'crime-safety':       'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80',
        'local-news':         'https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=800&q=80',
        'tourism':            'https://images.unsplash.com/photo-1539037116277-4db20889f2d4?w=800&q=80',
        'business':           'https://images.unsplash.com/photo-1556761175-4b46a572b786?w=800&q=80',
      };
      db.articles.unshift({ id:`evg_${Date.now()}_${added}`, title:a.title, arabic_title:a.title, summary:a.summary, arabic_summary:a.summary, content:a.content, arabic_content:a.content, category:a.cat, arabic_slug:slug, tags:a.tags, image_url: CAT_IMAGES[a.cat]||'https://images.unsplash.com/photo-1539037116277-4db20889f2d4?w=800&q=80', source:'evergreen', isEvergreen:true, status:'published', views:0, createdAt:new Date().toISOString(), updatedAt:new Date().toISOString() });
      added++;
    }
    fs.writeFileSync(dbPath, JSON.stringify(db, null, 2));
    res.json({ ok:true, added, skipped, total:db.articles.length });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// FIX IMAGES — GET /api/fix-evergreen-images?key=espana2025
app.get('/api/fix-evergreen-images', (req, res) => {
  if (req.query.key !== 'espana2025') return res.status(403).json({error:'forbidden'});
  try {
    const CAT_IMAGES = {
      'immigration':        'https://images.unsplash.com/photo-1436491865332-7a61a109cc05?w=800&q=80',
      'residency':          'https://images.unsplash.com/photo-1568992687947-868a62a9f521?w=800&q=80',
      'jobs':               'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80',
      'housing':            'https://images.unsplash.com/photo-1560518883-ce09059eeffa?w=800&q=80',
      'education':          'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=800&q=80',
      'cost-of-living':     'https://images.unsplash.com/photo-1579621970563-ebec7560ff3e?w=800&q=80',
      'government-benefits':'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800&q=80',
      'crime-safety':       'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80',
      'local-news':         'https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=800&q=80',
      'tourism':            'https://images.unsplash.com/photo-1539037116277-4db20889f2d4?w=800&q=80',
      'business':           'https://images.unsplash.com/photo-1556761175-4b46a572b786?w=800&q=80',
    };
    const dbPath = fs.existsSync(DB_PATH) ? DB_PATH : DB_LOCAL;
    const db = JSON.parse(fs.readFileSync(dbPath, 'utf8'));
    let fixed = 0;
    (db.articles||[]).forEach(a => {
      if (!a.image_url && CAT_IMAGES[a.category]) {
        a.image_url = CAT_IMAGES[a.category];
        fixed++;
      }
    });
    fs.writeFileSync(dbPath, JSON.stringify(db, null, 2));
    res.json({ ok:true, fixed, total: db.articles.length });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// EVERGREEN ENDPOINT — moved here before 404 handler
// ============================================================
app.get('/api/gen-evergreen', async (req, res) => {
  if (req.query.key !== 'espana2025') return res.status(403).json({error:'forbidden'});
  const startIdx = parseInt(req.query.start || '0');
  const count    = parseInt(req.query.count || '1');  // default 1 للـ free model
  const topics   = EVERGREEN_TOPICS.slice(startIdx, startIdx + count);

  res.setHeader('Content-Type', 'text/plain; charset=utf-8');
  res.setHeader('Transfer-Encoding', 'chunked');
  res.write(`🚀 بدء توليد ${topics.length} مقالات Evergreen (من ${startIdx})...\n\n`);

  const results = [];
  for (let i = 0; i < topics.length; i++) {
    const topic = topics[i];
    res.write(`[${startIdx+i+1}/20] 📝 ${topic.title.substring(0,50)}...\n`);
    try {
      const data = await generateEvergreen(topic);
      const arabic_slug = slugifyAr(data.title);
      const db = JSON.parse(fs.readFileSync(fs.existsSync(DB_PATH) ? DB_PATH : DB_LOCAL, 'utf8'));
      const exists = (db.articles||[]).some(a => a.arabic_slug === arabic_slug || a.title === data.title);
      if (exists) {
        res.write(`  ⏭️  موجود بالفعل — تخطي\n`);
        results.push({title:data.title, status:'skipped'});
        continue;
      }
      const article = {
        id: `evg_${Date.now()}_${i}`,
        title: data.title, arabic_title: data.title,
        summary: data.summary||'', arabic_summary: data.summary||'',
        content: data.content||'', arabic_content: data.content||'',
        category: topic.cat, arabic_slug,
        tags: data.tags||[], source: 'evergreen', isEvergreen: true,
        status: 'published', views: 0,
        createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(),
      };
      db.articles = db.articles || [];
      db.articles.unshift(article);
      const dbPath = fs.existsSync(DB_PATH) ? DB_PATH : DB_LOCAL;
      fs.writeFileSync(dbPath, JSON.stringify(db, null, 2));
      res.write(`  ✅ تم الحفظ — ${arabic_slug}\n`);
      results.push({title:data.title, status:'ok'});
    } catch(e) {
      res.write(`  ❌ خطأ: ${e.message.substring(0,100)}\n`);
      results.push({title:topic.title, status:'error', error:e.message});
    }
    if (i < topics.length - 1) {
      res.write(`  ⏳ انتظار 90 ثانية للـ rate limit...\n`);
      await new Promise(r => setTimeout(r, 90000));
    }
  }
  const ok = results.filter(r=>r.status==='ok').length;
  res.write(`\n✅ اكتمل: ${ok}/${topics.length} مقال\n`);
  res.write(`الخطوة التالية: /api/gen-evergreen?key=espana2025&start=${startIdx+count}&count=5\n`);
  res.end();
});

