function slugify(str) {
  return str
    .toLowerCase()
    .replace(/[\u0600-\u06FF\s]+/g, match => match.replace(/\s+/g, '-'))
    .replace(/[^\u0600-\u06FFa-z0-9-]/g, '')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 80) || `article-${Date.now()}`;
}

